import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Grid } from '@mui/material';
import response from './response.json';

interface PlatformPosts {
  name: string;
  posts: number;
}

interface WeekOverview {
  day: string;
  platforms: PlatformPosts[];
}

interface WidgetData {
  weekOverview: WeekOverview[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const { weekOverview } = widgetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1F2937' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" sx={{ color: '#F3F4F6', mb: 1 }}>
            Social Media Posts Overview
          </Typography>
          <Grid container spacing={1}>
            {weekOverview.map((dayData, index) => (
              <Grid item xs={12} key={index}>
                <Box sx={{ mb: 1 }}>
                  <Typography variant="body1" sx={{ color: '#9CA3AF' }}>
                    {dayData.day}
                  </Typography>
                  <Stack direction="row" spacing={0.5}>
                    {dayData.platforms.map((platform, idx) => (
                      <Chip
                        key={idx}
                        label={`${platform.name}: ${platform.posts}`}
                        sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#4B5563', color: '#F3F4F6' }}
                      />
                    ))}
                  </Stack>
                </Box>
              </Grid>
            ))}
          </Grid>
        </Stack>
      </CardContent>
    </Card>
  );
}
